        var viewPresentationUrl = '/ParagonLS/CMA/ViewPresentation.mvc/Generate/0';
        var showUrl = '/ParagonLS/CMA/Preview.mvc/Show';

        var _statusText = '';

        var pageOffsetHeight = 55;
        var _adjAmount = 255;

        $(function() {
            resizeMasterPage();
            $(window).bind('resize', resizeMasterPage);
            window.__rootWindow = window.findRootWindow();

            $("a.f-form-tooltip").qtip({ style: { name: "cream", tip: true }, position: { corner: { target: "topMiddle", tooltip: "bottomRight" }, adjust: { screen: true}} });
            $('.tooltip').each(function() {
                $(this).qtip({
                    content: $(this).html()
                })
                .html('');
            });
            $('#generate').click(function() {
                parent.Focus.Breadcrumb.navigateWithSelect("cma-6-presentation", viewPresentationUrl + '?themeNumber=' + parent.Focus.ClientCatalog.data['cma-4-theme_Theme']);
            });
            $('#preview').click(function() {
                var menuID = parent.$('#CurrentMenuId').val();
                var value = parent.Focus.ClientCatalog.data['cma-1-subjectproperty_MlsNumber'];
                if (String(menuID).indexOf("cma-5") == -1) {
                    menuID = "cma-5-coverpage";
                }
                var pointer = window.__rootWindow.ObjectRegistry.add(parent);
                window.__rootWindow.$.fn.colorbox({
                    href: showUrl + '/' + menuID + '?pointer=' + pointer + '&themeNumber=' + parent.Focus.ClientCatalog.data['cma-4-theme_Theme'],
                    open: true,
                    iframe: true,
                    width: 819,
                    height: 700,
                    title: 'CMA Presentation',
                    close: '<button id="Close">Close</button>',
                    onClosed: false
                });
            });
            if(!!parent.Focus.Breadcrumb == true) {
                parent.Focus.Breadcrumb.initialize(this);
                if(parent.Focus.Breadcrumb.data.length == 0 || 
                    (parent.Focus.Breadcrumb.data.length == 1 && parent.Focus.Breadcrumb.data[0] == parent.$('#CurrentMenuId').val())) {
                    $('#navBack')
                    .children(':first')
                    .attr('class', 'backOff');
                }
            }
            $('#debugOutput').click(function() {
                parent.Focus.ClientCatalog.__outputDebug();
            });
            $('#clientSave').click(function() {
                javascript:parent.Focus.ClientCatalog.save(window, window.packageForm)
            });

            if(!!parent.Focus.ClientCatalog == true) {
                parent.Focus.ClientCatalog.addSave(function(catalog) {

    parent.$("#cma-1-name").parent().attr("rel", $("#PresentationName").val().length > 0 ? "completedStep" : "normalItem");
    catalog.storeValue('PresentationName', catalog.helper.getValueById('PresentationName', window));

                });
                parent.Focus.ClientCatalog.addValidate(function(catalog) {

                    return true; //default to true if page doesn't implement
                });
                parent.Focus.ClientCatalog.addLoad(function(catalog) {

    catalog.helper.setValueById('PresentationName', catalog.loadValue('PresentationName'), window);
    $("#PresentationName").val().length > 0 ? $("#Next").removeAttr("disabled") : $('#Next').attr("disabled", true);
    $("#PresentationName").val().length > 0 ? $("#navSkip").children(0).attr('className', 'skipOff') : $('#navSkip').children(0).attr('className', 'skipOn');

                });
            }
            else if (Focus.ClientCatalog)
            {
                Focus.ClientCatalog.addSave(function (catalog) {

                }); 
                Focus.ClientCatalog.addValidate(function(catalog) {

                    return true; //default to true if page doesn't implement
                });                
            }
            if (_statusText.length > 0) {
                $.jGrowl(_statusText, { header: 'ALERT', group: 'jgrowl-alert' });
            }
            if(!!parent.Focus.ClientCatalog == true) {
                parent.Focus.ClientCatalog.attemptLoad();
            }
        });
    function resizeMasterPage() 
    {       
        var height = $(window).height() - pageOffsetHeight;

        var is_ipad = navigator.userAgent.match(/iPad/i) != null;
        if(is_ipad){
            height = parent.parent.window.innerHeight - _adjAmount; //iPad fix
        }
        $('.f-form-scroll').height(height);
    }





    $(function() {
        $('#PresentationName').keypress(parent.__dirtyBitTracker.setDirtyBit);

        $('#navSkip').click(function () {
            var presName = $("#PresentationName").val();
            parent.$("#cma-1-name").parent().attr("rel", presName.length > 0 ? "completedStep" : "normalItem");
            if (presName.length == 0) {
                parent.Focus.ClientCatalog.data["cma-1-name_PresentationName"] = '';
                parent.Focus.Breadcrumb._isSkip = true;
            }
            parent.Focus.Breadcrumb.navigateToNext();
        });
        $("#PresentationName").bind('paste', function(e) {
            $("#navSkip").children(0).attr('className', 'skipOff');
        });

        $('#Next').click(function () {
            parent.$("#cma-1-name").parent().attr("rel", "completedStep");
            parent.Focus.Breadcrumb.navigateToNext();
        });
        $("#PresentationName").blur(function(e) {
            parent.Focus.ClientCatalog.data["cma-1-name_PresentationName"] = $("#PresentationName").val();
        });
        $("#PresentationName").keyup(function(e) {
            $("#PresentationName").val().length > 0 ? $("#Next").removeAttr("disabled") : $('#Next').attr("disabled", true);
            $("#PresentationName").val().length > 0 ? $("#navSkip").children(0).attr('className', 'skipOff') : $('#navSkip').children(0).attr('className', 'skipOn');
            if (e.keyCode == 13 && $("#PresentationName").val().length > 0) {
                $("#Next").click();
            }
        });
    });



